function has(n){var t={};return"numbers"==n||"digits"==n||"num"==n?"(?=.*[0-9])":"letters"==n||"char"==n?"(?=.*[a-zA-Z])":t}function hasString(n){return"(?=.*\\b"+n+"\\b.*)"}function notString(n){return"(?=^(?!.*"+n+").*$)"}function not(n){var t={};return"numbers"==n||"digits"==n||"num"==n?"(?=.*^([^0-9]*)$)":"letters"==n||"char"==n?"(?=.*^([^a-zA-Z]*)$)":t}function or(){return"|"}function atLeastOne(n){return new RegExp("(?=.*"+n+"+)","g")}function wordSize(n){return new RegExp("(?=[a-zA-Z]{"+n+"})","gi")}function showRegex(type){return eval(type)}
